head.script:
tailwind.config = {
  darkMode: "class",
  theme: {
    extend: {
      colors: {
        "primary": "#a03b00",
        "primary-dark": "#c94c00",
        "surface": "#f9f9f9",
        "surface-container": "#f3f3f3",
        "on-surface": "#1a1c1c",
        "on-surface-variant": "#594138",
        "secondary": "#5f5e5e",
        "background": "#f9f9f9",
        "inverse-surface": "#2f3131"
      },
      fontFamily: { "headline": ["Public Sans"], "body": ["Public Sans"], "label": ["Public Sans"] },
      borderRadius: {"DEFAULT": "0.25rem", "lg": "0.5rem", "xl": "0.75rem", "2xl": "1rem", "full": "9999px"},
    },
  },
}

body.script:
let conversationHistory = [];
let userProfile = { age: null, monthly_income: null, occupation: null, state: null, family_size: 4 };
let isListening = false;
let bookmarkedSchemes = JSON.parse(localStorage.getItem('bookmarkedSchemes') || '[]');

// Dark Mode
function toggleDarkMode() {
  const body = document.body;
  const btn = document.getElementById('dark-mode-btn');
  const isDark = body.classList.contains('dark');

  if (isDark) {
    body.classList.remove('dark');
    localStorage.setItem('darkMode', 'false');
    btn.innerHTML = 'dark_mode';
  } else {
    body.classList.add('dark');
    localStorage.setItem('darkMode', 'true');
    btn.innerHTML = 'light_mode';
  }

  // Update mobile nav
  const mobileNav = document.querySelector('.mobile-nav');
  if (mobileNav) mobileNav.classList.toggle('dark');
}

// Load dark mode preference
if (localStorage.getItem('darkMode') === 'true') {
  document.body.classList.add('dark');
  document.getElementById('dark-mode-btn').innerHTML = 'light_mode';
}

// Bookmarks
function toggleBookmark(schemeName, event) {
  event.stopPropagation();
  const idx = bookmarkedSchemes.indexOf(schemeName);
  if (idx > -1) {
    bookmarkedSchemes.splice(idx, 1);
    showToast('Removed from bookmarks', 'removed');
  } else {
    bookmarkedSchemes.push(schemeName);
    showToast('Added to bookmarks!', 'added');
  }
  localStorage.setItem('bookmarkedSchemes', JSON.stringify(bookmarkedSchemes));
  updateBookmarkCount();
  if (typeof renderSchemes === 'function') renderSchemes();
}

function isBookmarked(schemeName) {
  return bookmarkedSchemes.includes(schemeName);
}

function updateBookmarkCount() {
  const badge = document.getElementById('bookmark-count');
  if (bookmarkedSchemes.length > 0) {
    badge.textContent = bookmarkedSchemes.length;
    badge.classList.remove('hidden');
  } else {
    badge.classList.add('hidden');
  }
}

function showBookmarks() {
  if (bookmarkedSchemes.length === 0) {
    showToast('No bookmarked schemes yet', 'info');
    return;
  }
  // Navigate to schemes with filter
  window.location.href = '/schemes?filter=bookmarked';
}

function showToast(message, type = 'info') {
  const toast = document.createElement('div');
  toast.className = `toast fixed top-24 right-6 z-[2000] px-6 py-4 rounded-2xl shadow-2xl font-medium text-sm flex items-center gap-3`;

  if (type === 'added') {
    toast.classList.add('bg-gradient-to-r', 'from-green-500', 'to-green-600', 'text-white');
    toast.innerHTML = 'bookmark_added' + message;
  } else if (type === 'removed') {
    toast.classList.add('bg-gradient-to-r', 'from-gray-500', 'to-gray-600', 'text-white');
    toast.innerHTML = 'bookmark_remove' + message;
  } else {
    toast.classList.add('bg-gradient-to-r', 'from-[#a03b00]', 'to-[#c94c00]', 'text-white');
    toast.innerHTML = 'info' + message;
  }

  document.body.appendChild(toast);
  setTimeout(() => toast.remove(), 3000);
}

function shareScheme(schemeName, schemeDetails, event) {
  event.stopPropagation();
  const text = `*${schemeName}*\n\n${schemeDetails}\n\nCheck eligibility on AI Sahayak!`;

  if (navigator.share) {
    navigator.share({
      title: schemeName,
      text: text,
      url: window.location.origin
    });
  } else {
    // Fallback: copy to clipboard
    navigator.clipboard.writeText(text).then(() => {
      showToast('Copied to clipboard! Share via WhatsApp', 'info');
    });
  }
}

// Quick Profile Setup
function showQuickProfile() {
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.4);backdrop-filter:blur(8px);z-index:1000;display:flex;align-items:center;justify-content:center;padding:20px;';
  modal.innerHTML = `





Quick Profile Setup

          close






          उम्र | Age




          मासिक आय | Monthly Income (₹)




          व्यवसाय | Occupation

            चुनें
            किसान | Farmer
            खेत मजदूर | Agricultural Laborer
            दिहाड़ी मजदूर | Daily Wage Worker
            छोटा व्यापारी | Small Trader
            अन्य | Other




          राज्य | State

            चुनें
            Uttar Pradesh
            Bihar
            Madhya Pradesh
            Rajasthan
            Odisha
            Maharashtra
            West Bengal
            Jharkhand



          Save Profile


    `;
  modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });
  document.body.appendChild(modal);
}

function saveQuickProfile() {
  const age = document.getElementById('quick-age').value;
  const income = document.getElementById('quick-income').value;
  const occupation = document.getElementById('quick-occupation').value;
  const state = document.getElementById('quick-state').value;

  if (!age || !income || !occupation || !state) {
    showToast('Please fill all fields', 'info');
    return;
  }

  userProfile = { age: parseInt(age), monthly_income: parseFloat(income), occupation, state, family_size: 4 };
  localStorage.setItem('userProfile', JSON.stringify(userProfile));

  document.querySelector('[style]').remove();
  showToast('Profile saved! Checking eligibility...', 'added');
  loadEligibility();
}

// Initialize
updateBookmarkCount();
if (localStorage.getItem('userProfile')) {
  userProfile = JSON.parse(localStorage.getItem('userProfile'));
  setTimeout(loadEligibility, 500);
}

function loadEligibility() {
  if (!userProfile.age || !userProfile.monthly_income || !userProfile.occupation || !userProfile.state) return;
  fetch('/api/eligibility', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify(userProfile)
  }).then(r => r.json()).then(data => {
    const results = data.rule_based || {};
    const eligible = Object.entries(results).filter(([k, v]) => v);
    if (eligible.length > 0) {
      document.getElementById('eligible-panel').classList.remove('hidden');
      const names = { pmkisan: 'PM-KISAN', mgnrega: 'MGNREGA', mudra: 'MUDRA Loan', awas: 'PM Awas Yojana', ayushman: 'Ayushman Bharat', ujjwala: 'PM Ujjwala' };
      const icons = { pmkisan: 'agriculture', mgnrega: 'construction', mudra: 'account_balance', awas: 'home', ayushman: 'health_and_safety', ujjwala: 'local_fire_department' };
      document.getElementById('eligible-schemes-list').innerHTML = eligible.map(([k]) => `


          ${icons[k] || 'check_circle'}
          ${names[k] || k}
        `).join('');
    }
  });
}

function addChatBubble(text, isUser = false, speakNow = false) {
  const container = document.getElementById('chat-container');
  const bubble = document.createElement('div');
  bubble.className = `flex items-start gap-3 animate-fade ${isUser ? 'flex-row-reverse' : ''}`;
  const iconClass = isUser ? 'bg-gradient-to-br from-[#a03b00] to-[#c94c00] ring-2 ring-[#a03b00]/20' : 'bg-[#a03b00]/10 ring-2 ring-[#a03b00]/10';
  const textClass = isUser ? 'bg-gradient-to-br from-[#a03b00] to-[#c94c00] text-white shadow-md chat-bubble-user' : 'bg-[#f8f8f8] text-[#1a1c1c] shadow-sm chat-bubble-ai';
  bubble.innerHTML = `


      ${isUser ? 'person' : 'smart_toy'}




${text}
    `;
  container.appendChild(bubble);
  container.scrollTop = container.scrollHeight;
}

function addTyping() {
  const container = document.getElementById('chat-container');
  const div = document.createElement('div');
  div.id = 'typing';
  div.className = 'flex items-start gap-3';
  div.innerHTML = `
smart_toy
`;
  container.appendChild(div);
  container.scrollTop = container.scrollHeight;
}

function removeTyping() { const t = document.getElementById('typing'); if (t) t.remove(); }

async function sendChat() {
  const input = document.getElementById('chat-input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';
  addChatBubble(msg, true, false);
  conversationHistory.push({ role: 'user', content: msg });
  addTyping();
  extractProfile(msg);
  try {
    const res = await fetch('/api/chat', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ message: msg, history: conversationHistory.slice(-8), user_profile: userProfile })
    });
    if (!res.ok) {
      throw new Error(`HTTP ${res.status}: ${res.statusText}`);
    }
    const data = await res.json();
    removeTyping();
    const reply = data.response || 'Kuch problem hui, please try again.';
    addChatBubble(reply, false, true);
    conversationHistory.push({ role: 'assistant', content: reply });
  } catch(e) {
    removeTyping();
    console.error('Chat error:', e);
    addChatBubble('Error: ' + e.message + '. Please try again.', false, false);
  }
}

function extractProfile(text) {
  const ageMatch = text.match(/(\d+)\s*(saal|years?|yrs?|वर्ष|umr)/i);
  if (ageMatch && !userProfile.age) {
    const a = parseInt(ageMatch[1]);
    if (a > 10 && a < 100) userProfile.age = a;
  }
  const incomeMatch = text.match(/(?:income|kamai|earning|₹|rs|paisa|maasik)?\s*(\d+)\s*(?:rupiya|rs|₹|per\s*month|monthly|maah|maasika)?/i);
  if (incomeMatch && !userProfile.monthly_income) {
    const inc = parseInt(incomeMatch[1]);
    if (inc > 100 && inc < 1000000) userProfile.monthly_income = inc;
  }
  const occMap = { 'farmer': 'farmer', 'kisan': 'farmer', 'mazdoor': 'daily_wage_laborer', 'laborer': 'agricultural_laborer', 'artisan': 'artisan', 'trader': 'small_trader' };
  for (const [k, v] of Object.entries(occMap)) { if (text.toLowerCase().includes(k) && !userProfile.occupation) { userProfile.occupation = v; break; } }
  const stateMap = { 'up': 'UP', 'uttar pradesh': 'UP', 'bihar': 'Bihar', 'mp': 'MP', 'madhya pradesh': 'MP', 'rajasthan': 'Rajasthan', 'odisha': 'Odisha', 'maharashtra': 'Maharashtra', 'west bengal': 'West Bengal', 'jharkhand': 'Jharkhand' };
  for (const [k, v] of Object.entries(stateMap)) { if (text.toLowerCase().includes(k) && !userProfile.state) { userProfile.state = v; break; } }
  if (userProfile.age && userProfile.monthly_income && userProfile.occupation && userProfile.state) {
    setTimeout(loadEligibility, 500);
  }
}

function toggleVoice() {
  if (!('webkitSpeechRecognition' in window)) {
    addChatBubble('Voice input not supported. Please type instead.', false, false);
    return;
  }
  if (isListening) {
    isListening = false;
    document.getElementById('voice-btn').classList.remove('listening');
    document.getElementById('voice-pulse').classList.remove('opacity-60');
    document.getElementById('voice-icon').textContent = 'mic';
    document.getElementById('listening-modal').style.display = 'none';
    return;
  }
  const recognition = new webkitSpeechRecognition();
  recognition.lang = 'hi-IN, en-IN';
  recognition.continuous = false;
  recognition.interimResults = false;
  isListening = true;
  document.getElementById('voice-btn').classList.add('listening');
  document.getElementById('voice-pulse').classList.add('opacity-60');
  document.getElementById('voice-icon').textContent = 'mic_off';
  document.getElementById('listening-modal').style.display = 'flex';
  recognition.start();
  recognition.onresult = (event) => {
    const transcript = event.results[0][0].transcript;
    document.getElementById('chat-input').value = transcript;
    isListening = false;
    document.getElementById('voice-btn').classList.remove('listening');
    document.getElementById('voice-pulse').classList.remove('opacity-60');
    document.getElementById('voice-icon').textContent = 'mic';
    document.getElementById('listening-modal').style.display = 'none';
    sendChat();
  };
  recognition.onerror = recognition.onend = () => {
    isListening = false;
    document.getElementById('voice-btn').classList.remove('listening');
    document.getElementById('voice-pulse').classList.remove('opacity-60');
    document.getElementById('voice-icon').textContent = 'mic';
    document.getElementById('listening-modal').style.display = 'none';
  };
}

let voicesLoaded = false;
let queuedTexts = [];

// Mobile Bottom Navigation
document.write(`



    home
    Home


    verified
    Eligibility


    folder_special
    Schemes


    person
    Profile


    support_agent
    Support


`);
